import React from 'react';
import './Team.css';

export default function Team({ navigate }) {
  return (
    <div className="fdt-page">
      <div className="fdt-hero">
        <span>Our Team</span>
        <h1>The People Behind <span>FuelDrop</span></h1>
        <p>A passionate team of engineers, operators, and fuel industry experts united by one mission.</p>
      </div>
      <section className="fdt-team fd-section">
        <div className="fd-container">
          <div className="fdt-grid">
            {TEAM.map((m, i) => (
              <div key={i} className="fdt-card">
                <div className="fdt-img-wrap"><img src={m.img} alt={m.name} /></div>
                <div className="fdt-info">
                  <h3>{m.name}</h3>
                  <span>{m.role}</span>
                  <p>{m.bio}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>
    </div>
  );
}
